sql:
SELECT AVG(d.age) AS average_age
FROM employees e
JOIN demographics d ON e.employee_id = d.employee_id;

external_knowledge:
- 'Received high praise multiple times' refers to employees with more than one rating score greater than 4; 
- 'Seasoned learners' refers to employees with more than one training record; 
- 'Recent growth spurt' refers to the period between '2022-01-01' and '2023-12-31'.
